import { createContext, useContext, type ReactNode } from "react";
import { createApiClient, type ApiClient, type ApiClientConfig } from "./client.js";

const ApiClientContext = createContext<ApiClient | null>(null);

export interface ApiProviderProps {
  config: ApiClientConfig;
  children: ReactNode;
}

export function ApiProvider({ config, children }: ApiProviderProps) {
  const client = createApiClient(config);
  return (
    <ApiClientContext.Provider value={client}>{children}</ApiClientContext.Provider>
  );
}

export function useApiClient(): ApiClient {
  const client = useContext(ApiClientContext);
  if (!client) {
    throw new Error("useApiClient must be used within an ApiProvider");
  }
  return client;
}
